    e.del_flag = '0'
     and e.dept_id = #{deptId}
     and e.period_id = #{periodId}
     and e.expense_no like concat('%', #{expenseNo}, '%')
     and e.expense_type = #{expenseType}
     and e.expense_content like concat('%', #{expenseContent}, '%')
