dept_id = #{deptId}, period_id = #{periodId}, expense_no = #{expenseNo}, expense_date = #{expenseDate}, expense_type = #{expenseType}, expense_content = #{expenseContent}, payment_method = #{paymentMethod}, expense_amount = #{expenseAmount}, advance_id = #{advanceId}, status = #{status}, verify_by = #{verifyBy}, verify_time = #{verifyTime}, del_flag = #{delFlag}, update_by = #{updateBy}, update_time = sysdate(), remark = #{remark},
