group by expense_type
order by totalAmount desc

select date_format(e.expense_date, '%Y-%m-%d') as dateStr, e.dept_id as deptId, d.dept_name as deptName, ifnull(sum(case when e.expense_type = '开支' then abs(e.expense_amount) else 0 end), 0) as expenseAmount, ifnull(sum(case when e.expense_type = '收入' then abs(e.expense_amount) else 0 end), 0) as incomeAmount from fin_expense e left join sys_dept d on e.dept_id = d.dept_id where e.del_flag = '0'
and e.dept_id in
#{deptId}
and e.expense_date >= #{startTime}
and e.expense_date <= #{endTime}
group by date_format(e.expense_date, '%Y-%m-%d'), e.dept_id, d.dept_name order by dateStr, e.dept_id

select e.dept_id as deptId, d.dept_name as deptName, ifnull(sum(e.expense_amount), 0) as totalAmount from fin_expense e left join sys_dept d on e.dept_id = d.dept_id where e.del_flag = '0'
and e.dept_id in
#{deptId}
and e.expense_date >= #{startTime}
and e.expense_date <= #{endTime}
group by e.dept_id, d.dept_name order by totalAmount desc

